export type GetUploadUrlMutationResult = NonNullable<
  Awaited<ReturnType<typeof getUploadUrl>>
>;
export type GetUploadUrlMutationBody = BodyType<UploadUrlRequest>;
export type GetUploadUrlMutationError = ErrorType<ErrorResponse>;

/**
 * @summary Get a presigned GCS PUT URL for direct meal photo upload.
Step 1 of 2: call this to obtain uploadUrl and objectKey.
Step 2 of 2: PUT the image bytes directly to uploadUrl (Content-Type: image/jpeg).
Photo upload is independent of food analysis — run both in parallel.

 */
export const useGetUploadUrl = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof getUploadUrl>>,
    TError,
    { data: BodyType<UploadUrlRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof getUploadUrl>>,
  TError,
  { data: BodyType<UploadUrlRequest> },
  TContext
> => {
  return useMutation(getGetUploadUrlMutationOptions(options));
};

/**
 * @summary Serve a stored meal photo by its object key
 */
export const getGetStorageObjectUrl = (objectKey: string) => {
  return `/api/storage/objects/${objectKey}`;
};

export const getStorageObject = async (
  objectKey: string,
  options?: RequestInit,
): Promise<Blob> => {
  return customFetch<Blob>(getGetStorageObjectUrl(objectKey), {
    ...options,
    method: "GET",
  });
};

export const getGetStorageObjectQueryKey = (objectKey: string) => {
  return [`/api/storage/objects/${objectKey}`] as const;
};

export const getGetStorageObjectQueryOptions = <
  TData = Awaited<ReturnType<typeof getStorageObject>>,
  TError = ErrorType<ErrorResponse>,
>(
  objectKey: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getStorageObject>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetStorageObjectQueryKey(objectKey);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getStorageObject>>
  > = ({ signal }) =>
    getStorageObject(objectKey, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!objectKey,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getStorageObject>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetStorageObjectQueryResult = NonNullable<
  Awaited<ReturnType<typeof getStorageObject>>
>;
export type GetStorageObjectQueryError = ErrorType<ErrorResponse>;

/**
 * @summary Serve a stored meal photo by its object key
 */

export function useGetStorageObject<
  TData = Awaited<ReturnType<typeof getStorageObject>>,
  TError = ErrorType<ErrorResponse>,
>(
  objectKey: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getStorageObject>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetStorageObjectQueryOptions(objectKey, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
